sub extract_text {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Extract text from each page
    my $text = '';
    for my $page_num (1 .. $pdf->pages) {
        my $page = $pdf->page($page_num);
        my $content = $page->textcontent;
        $text .= $content;
    }

    return $text;
}

